// Build the Meta Ads campaign structure from the exported payload.
// Phase 1: transform only (no publish). page_id / adset_id / creative_id and
// act_<AD_ACCOUNT_ID> are bound at publish time against a Meta Sandbox account.
const input = $input.first().json;
const p = input.payload || {};
const campaign = p.campaign || {};
const brand = p.brand || {};
const strategy = p.strategy || {};
const seg = strategy.segmentation || {};
const audience = strategy.audience || {};
const adCopies = Array.isArray(p.adCopies) ? p.adCopies : [];
const creatives = Array.isArray(p.creativeAssets) ? p.creativeAssets : [];

function metaObjective(obj) {
  const s = (obj || '').toLowerCase();
  if (/(sell|sale|purchase|vend|compra)/.test(s)) return 'OUTCOME_SALES';
  if (/lead/.test(s)) return 'OUTCOME_LEADS';
  if (/(aware|reconoc|brand)/.test(s)) return 'OUTCOME_AWARENESS';
  if (/app/.test(s)) return 'OUTCOME_APP_PROMOTION';
  if (/(engag|interac)/.test(s)) return 'OUTCOME_ENGAGEMENT';
  return 'OUTCOME_TRAFFIC';
}

const COUNTRY = {
  'mexico':'MX','méxico':'MX','colombia':'CO','guatemala':'GT','el salvador':'SV',
  'chile':'CL','peru':'PE','perú':'PE','argentina':'AR','brazil':'BR','brasil':'BR',
  'ecuador':'EC','costa rica':'CR','panama':'PA','panamá':'PA','uruguay':'UY',
  'paraguay':'PY','bolivia':'BO','honduras':'HN','nicaragua':'NI',
  'dominican republic':'DO','venezuela':'VE'
};
function toCountryCodes(locations) {
  const names = Array.isArray(locations) ? locations : [];
  const codes = [];
  for (const n of names) {
    const key = String(n).trim().toLowerCase();
    if (COUNTRY[key]) codes.push(COUNTRY[key]);
  }
  return codes.length ? [...new Set(codes)] : ['MX','CO','CL','PE','AR'];
}

function ctaType(cta) {
  const s = (cta || '').toLowerCase();
  if (/(pre-?order|preorden)/.test(s)) return 'ORDER_NOW';
  if (/(shop|comprar|\bbuy\b)/.test(s)) return 'SHOP_NOW';
  if (/sign/.test(s)) return 'SIGN_UP';
  if (/(learn|saber|más|mas)/.test(s)) return 'LEARN_MORE';
  return 'LEARN_MORE';
}

const CAMPAIGN_NAME = campaign.name || (brand.name ? brand.name + ' Campaign' : 'Polyedro Campaign');

const metaCampaign = {
  name: CAMPAIGN_NAME,
  objective: metaObjective(campaign.objective),
  status: 'PAUSED',
  special_ad_categories: [],
};

const adSet = {
  name: CAMPAIGN_NAME + ' — Ad Set',
  status: 'PAUSED',
  billing_event: 'IMPRESSIONS',
  optimization_goal: 'LINK_CLICKS',
  daily_budget: 50000,
  targeting: {
    geo_locations: {
      countries: toCountryCodes((seg.locations && seg.locations.length) ? seg.locations : audience.locations),
    },
    age_min: seg.ageMin || 18,
    age_max: seg.ageMax || 65,
    ...(Array.isArray(seg.genders) && seg.genders.length ? { genders: seg.genders } : {}),
  },
};

const creativeByVariant = {};
for (const c of creatives) creativeByVariant[c.variant] = c;

const ads = adCopies.map((copy) => {
  const creative = creativeByVariant[copy.variant] || creatives[0] || {};
  const label = [CAMPAIGN_NAME, String(copy.language || '').toUpperCase(), 'Var ' + String(copy.variant || '').toUpperCase()].filter(Boolean).join(' — ');
  return {
    language: copy.language,
    variant: copy.variant,
    adCreative: {
      name: label + ' — Creative',
      object_story_spec: {
        link_data: {
          message: copy.primaryText || '',
          name: copy.headline || '',
          description: copy.description || '',
          link: brand.website || 'https://example.com',
          picture: creative.imageUrl || null,
          call_to_action: { type: ctaType(copy.callToAction) },
        },
      },
    },
    ad: { name: label, status: 'PAUSED' },
  };
});

const metaAds = {
  apiVersion: 'v25.0',
  graphBase: 'https://graph.facebook.com/v25.0',
  note: 'Built by Polyedro /abs (Phase 1: transform only). Publish to a Meta Sandbox Ad Account with all objects PAUSED. Bind page_id, adset_id, creative_id and act_<AD_ACCOUNT_ID> at publish time.',
  publishOrder: ['campaign', 'adSet', 'adCreatives', 'ads'],
  campaign: metaCampaign,
  adSet,
  ads,
  counts: { adCopies: adCopies.length, creatives: creatives.length, ads: ads.length },
};

return [{ json: {
  brandId: input.brandId,
  campaignId: input.campaignId,
  target: input.target,
  receivedAt: input.receivedAt,
  metaAds,
} }];
